const express = require('express');
const mongoose = require('mongoose');
const bodyParser = require('body-parser');

// Connect to MongoDB
mongoose.connect('mongodb://localhost/your_database', { useNewUrlParser: true, useUnifiedTopology: true });

// Define the schema for your data model (replace with your actual model)
const YourModelSchema = new mongoose.Schema({
  // define your fields here
});

// Create a Mongoose model based on the schema
const YourModel = mongoose.model('YourModel', YourModelSchema);

// Initialize Express app
const app = express();
app.use(bodyParser.json());

// API endpoint to search data in MongoDB
app.get('/search', async (req, res) => {
  try {
    const query = req.query; // get the search filters from API request's query parameters

    const result = await YourModel.find(query);
    res.json(result);
  } catch (err) {
    console.error(err);
    res.status(500).send('Error fetching data');
  }
});

// Start the server
app.listen(3000, () => console.log('Server started on port 3000'));